{"operationName":"AcidCarouselSearch","variables":{"input":{"basicSearchInput":{"nbAdults":2},"acidCarouselContext":{"acidCarouselId":64}},"shouldFetchFacilities":false},"extensions":{},"query":"query AcidCarouselSearch($input: AcidCarouselInput!, $shouldFetchFacilities: Boolean!) {
  searchQueries {
    searchAcidCarousel(input: $input) {
      title
      subtitle
      acidCards {
        basicPropertyData {
          id
          name
          photos {
            main {
              highResUrl {
                relativeUrl
                __typename
              }
              lowResJpegUrl {
                relativeUrl
                __typename
              }
              __typename
            }
            __typename
          }
          location {
            countryCode
            country
            city
            __typename
          }
          pageName
          reviews {
            reviewsCount
            totalScore
            __typename
          }
          __typename
        }
        priceDisplayInfoIrene {
          displayPrice {
            amountPerStay {
              amountRounded
              __typename
            }
            __typename
          }
          __typename
        }
        landingOptions {
          destId
          destType
          __typename
        }
        facilitiesData @include(if: $shouldFetchFacilities) {
          id
          name
          type
          __typename
        }
        districtName
        isGenius
        __typename
      }
      hasAvailability
      landingOptions {
        page
        selectedFilters
        destId
        destType
        checkin
        checkout
        nbAdults
        nbChildren
        childrenAges
        nbRooms
        sorter
        travelPurpose
        __typename
      }
      __typename
    }
    __typename
  }
}
"}

