    surveyId
    surveyName
    dismissedDurationInSeconds
    dismissibleSurveyNames
    surveyQuestions {
      questionText
      questionType
      isRequired
      ... on RatingScaleQuestion {
        questionId
        items {
          label
          value
          __typename
